mask = df['isim'] == 'serap'
kupe_series = df.loc[mask, 'kupe_no']
if not kupe_series.empty:
    final_result = kupe_series.values[0]
else:
    final_result = None

filtered = df[(df['tarih'].dt.year == 2025) & (df['tarih'].dt.month == 2)]

if filtered.empty:
    final_result = None
else:
    milk_by_cow = filtered.groupby('isim')['sut_miktari'].sum()
    min_cow = milk_by_cow.idxmin()
    min_amount = milk_by_cow.min()
    final_result = {'isim': min_cow, 'sut_miktari': min_amount}

grouped = (
    df.groupby(['tarih', 'kupe_no'])['sut_miktari']
      .sum()
      .reset_index(name='total')
)

if grouped.empty:
    final_result = None
else:
    max_idx = grouped['total'].idxmax()
    final_result = grouped.loc[max_idx, 'tarih']

daily_total = df.groupby(df['tarih'].dt.normalize())['sut_miktari'].sum()
rolling_avg = daily_total.rolling(window=7).mean()

if not rolling_avg.empty:
    max_end_date = rolling_avg.idxmax()
    max_start_date = max_end_date - pd.Timedelta(days=6)
    max_value = rolling_avg.max()
    final_result = {
        'start_date': max_start_date,
        'end_date': max_end_date,
        'moving_average': max_value
    }
else:
    final_result = None

daily_total = df.groupby(df['tarih'].dt.normalize())['sut_miktari'].sum().sort_index()
diff = daily_total.diff()
if diff.empty:
    final_result = None
else:
    final_result = diff.abs().idxmax()
